insert into agencies (code, name, description, accent_color, phone, email, address) values
  ('TRA', 'Tanzania Revenue Authority', 'Collects national tax revenue and administers taxpayer registration, VAT, and customs.', '#0B6E4F', '+255 22 219 9000', 'info@tra.go.tz', 'TRA House, Dar es Salaam'),
