  ('IMM', 'Immigration Services Department', 'Processes passports, visas, and residence permits for citizens and foreign nationals.', '#0B6E4F', '+255 22 285 0575', 'info@immigration.go.tz', 'Ghana Avenue, Dar es Salaam'),
  ('RITA', 'Registration, Insolvency & Trusteeship Agency', 'Registers births, deaths, marriages, and manages trusteeship services.', '#8A4B08', '+255 22 286 3475', 'info@rita.go.tz', 'Upanga, Dar es Salaam'),
  ('OSHA', 'Occupational Safety & Health Authority', 'Regulates workplace safety and mandatory employer registration.', '#0A4D68', '+255 22 286 3072', 'info@osha.go.tz', 'Dar es Salaam'),
  ('NEMC', 'National Environment Management Council', 'Issues environmental impact and pollution permits for regulated activities.', '#0B6E4F', '+255 22 277 4852', 'info@nemc.or.tz', 'Regent Estate, Dar es Salaam'),
